(window.webpackJsonp=window.webpackJsonp||[]).push([[211],{838:function(t,n){t.exports="\x3c!-- \ntitle: A4-Matplotlib\nsort: \n--\x3e \n\n> `matplotlib`\n\n## 统计图\n\n```python\nimport matplotlib.pyplot as plt\n\n# 调整图\nplt.figure(figsize=(16,5))\t\t# 大小\nplt.title('title')\nplt.xlabel('index')\nplt.ylabel('count')\nplt.legend(['sin','cos'])\t\t\t# 图例\n\nx = np.arange(-10,10,0.1)\ny = np.sin(x)\n# 折线图\nplt.plot(x,y,'g')\t\t\t# 线色为绿\nplt.plot(x,y,'go')\t\t# 绿点\nplt.plot(x,y,'g--')\t\t# 绿虚线\nplt.show()\n\ny = pow(x,2)\n# 柱状图\nplt.bar(x,y)\n\n# 饼图\nplt.pie([2,5,3],labels=[1,2,3],autopct='%1.1f%%')\n\n# 散点图\nplt.scatter(x,y)\nc='', edgecolors='', alpha=0.5\t\t# 颜色\ns='', marker='x'\t\t# 大小与标志\n\n```\n\n## 图像\n\n```\tpython\n# 设置图形对象 ：窗口\nplt.figure('Figure Object 1',       # 图形对象名称  窗口左上角显示\n           figsize = (8, 6),        # 窗口大小\n           dpi = 120,               # 分辨率\n           facecolor = 'lightgray', # 背景色\n           )\nplt.subplot(5,3,i+1)\t# 行，列，索引\nplt.imshow(img)\t\t\t\t# 添加图片 cmap='gray' 灰度图\nplt.axis('on') \t\t\t\t# 是否显示坐标轴 on/off\nplt.colorbar()\t\t\t\t# 显示颜色图例\nplt.grid(False)\t\t\t\t# 是否显示网格线\nplt.title('image') \t\t# 图像题目\nplt.show()\n```\n\n"}}]);